package com.hospital.management.controller.billing;import com.hospital.management.model.Payment;import com.hospital.management.service.*;import com.hospital.management.service.impl.PaymentServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/billing/payment/receipt")public class PaymentReceiptServlet extends HttpServlet{private final PaymentService service;public PaymentReceiptServlet(){this(new PaymentServiceImpl());}public PaymentReceiptServlet(PaymentService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=BillingRequest.id(q.getParameter("id"));Payment p=id==null?null:service.getPayment(id,BillingRequest.user(q)).orElse(null);if(p==null){r.sendError(404);return;}q.setAttribute("payment",p);q.getRequestDispatcher("/WEB-INF/views/billing/payment-receipt.jsp").forward(q,r);}}
